# Category: insecure_auth

from flask import Flask, request, jsonify
from flask_jwt_extended import JWTManager, create_access_token, jwt_required, get_raw_jwt
from passlib.hash import sha256_crypt

app = Flask(__name__)
app.config['SECRET_KEY'] = 'super-secret'  # Change this to your own secret key
jwt = JWTManager(app)

users = {
    "user1": "password1",
    "user2": "password2"
}

@app.route('/register', methods=['POST'])
def register():
    if request.is_json and 'username' in request.json and 'password' in request.json:
        username = request.json['username']
        password = request.json['password']

        if username not in users:
            users[username] = sha256_crypt.encrypt(password)
            return jsonify({"status": "success", "message": f"User {username} registered"})
        else:
            return jsonify({"status": "error", "message": f"Username {username} already exists"})
    else:
        return jsonify({"status": "error", "message": "Invalid request format"})

@app.route('/login', methods=['POST'])
def login():
    if request.is_json and 'username' in request.json and 'password' in request.json:
        username = request.json['username']
        password = request.json['password']

        if username in users and sha256_crypt.verify(password, users[username]):
            access_token = create_access_token(identity=username)
            return jsonify({"status": "success", "access_token": access_token})
        else:
            return jsonify({"status": "error", "message": f"Invalid username or password for {username}"})
    else:
        return jsonify({"status": "error", "message": "Invalid request format"})

@app.route('/protected')
@jwt_required()
def protected():
    jwt = get_raw_jwt()
    identity = jwt['identity']  # You can access the user's username here
    return jsonify({"status": "success", "user": identity})

if __name__ == '__main__':
    app.run(debug=True)